class LRUCache {
    private final int capacity;
    private final Map<Integer, Node> map = new HashMap<>();
    private final Node head = new Node(0, 0); // dummy head
    private final Node tail = new Node(0, 0); // dummy tail

    public LRUCache(int capacity) {
        this.capacity = capacity;
        head.next = tail;
        tail.prev = head;
    }

    public int get(int key) {
        Node node = map.get(key);
        if (node == null) return -1;
        moveToFront(node);
        return node.val;
    }

    public void put(int key, int value) {
        Node node = map.get(key);
        if (node != null) {
            node.val = value;
            moveToFront(node);
        } else {
            node = new Node(key, value);
            map.put(key, node);
            addToFront(node);
            if (map.size() > capacity) {
                Node lru = tail.prev; // node before dummy tail
                removeNode(lru);
                map.remove(lru.key);
            }
        }
    }

    private void moveToFront(Node node) {
        removeNode(node);
        addToFront(node);
    }

    private void removeNode(Node node) {
        node.prev.next = node.next;
        node.next.prev = node.prev;
    }

    private void addToFront(Node node) {
        node.next = head.next;
        node.prev = head;
        head.next.prev = node;
        head.next = node;
    }

    private static class Node {
        int key, val;
        Node prev, next;
        Node(int k, int v) { key = k; val = v; }
    }
}

// Java built-in: LinkedHashMap approach
class LRUCacheSimple extends LinkedHashMap<Integer, Integer> {
    private final int capacity;
    public LRUCacheSimple(int capacity) {
        super(capacity, 0.75f, true); // accessOrder=true
        this.capacity = capacity;
    }
    public int get(int key) { return super.getOrDefault(key, -1); }
    public void put(int key, int value) { super.put(key, value); }
    @Override
    protected boolean removeEldestEntry(Map.Entry<Integer, Integer> eldest) {
        return size() > capacity;
    }
}

class Trie {
    private TrieNode root = new TrieNode();

    public void insert(String word) {
        TrieNode curr = root;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (curr.children[idx] == null)
                curr.children[idx] = new TrieNode();
            curr = curr.children[idx];
        }
        curr.isEnd = true;
    }

    public boolean search(String word) {
        TrieNode curr = root;
        for (char c : word.toCharArray()) {
            int idx = c - 'a';
            if (curr.children[idx] == null) return false;
            curr = curr.children[idx];
        }
        return curr.isEnd;
    }

    public boolean startsWith(String prefix) {
        TrieNode curr = root;
        for (char c : prefix.toCharArray()) {
            int idx = c - 'a';
            if (curr.children[idx] == null) return false;
            curr = curr.children[idx];
        }
        return true; // reached end of prefix without falling off
    }

    static class TrieNode {
        TrieNode[] children = new TrieNode[26];
        boolean isEnd;
    }
}

// Word search II: Trie + DFS on board
public List<String> findWords(char[][] board, String[] words) {
    Trie trie = new Trie();
    for (String w : words) trie.insert(w);
    Set<String> result = new HashSet<>();
    int m = board.length, n = board[0].length;
    boolean[][] visited = new boolean[m][n];
    for (int i = 0; i < m; i++)
        for (int j = 0; j < n; j++)
            dfsBoard(board, i, j, trie.root, new StringBuilder(), visited, result);
    return new ArrayList<>(result);
}
private void dfsBoard(char[][] board, int i, int j, Trie.TrieNode node,
                       StringBuilder path, boolean[][] visited, Set<String> result) {
    if (i < 0 || i >= board.length || j < 0 || j >= board[0].length ||
        visited[i][j]) return;
    int idx = board[i][j] - 'a';
    if (node.children[idx] == null) return; // prune
    visited[i][j] = true;
    path.append(board[i][j]);
    node = node.children[idx];
    if (node.isEnd) result.add(path.toString());
    int[][] dirs = {{0,1},{0,-1},{1,0},{-1,0}};
    for (int[] d : dirs) dfsBoard(board, i+d[0], j+d[1], node, path, visited, result);
    path.deleteCharAt(path.length() - 1);
    visited[i][j] = false;
}

class UnionFind {
    private int[] parent, rank;
    private int components;

    public UnionFind(int n) {
        parent = new int[n];
        rank = new int[n];
        components = n;
        for (int i = 0; i < n; i++) parent[i] = i;
    }

    public int find(int x) {
        if (parent[x] != x)
            parent[x] = find(parent[x]); // path compression
        return parent[x];
    }

    public boolean union(int x, int y) {
        int rx = find(x), ry = find(y);
        if (rx == ry) return false; // already connected
        if (rank[rx] < rank[ry]) parent[rx] = ry;
        else if (rank[rx] > rank[ry]) parent[ry] = rx;
        else { parent[ry] = rx; rank[rx]++; }
        components--;
        return true;
    }

    public boolean connected(int x, int y) {
        return find(x) == find(y);
    }

    public int getComponents() { return components; }
}

// Number of islands using Union-Find
public int numIslands(char[][] grid) {
    int m = grid.length, n = grid[0].length;
    UnionFind uf = new UnionFind(m * n);
    int islands = 0;
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] == '1') {
                islands++;
                // merge with adjacent '1' cells
                if (i > 0 && grid[i-1][j] == '1') {
                    if (uf.union(i*n+j, (i-1)*n+j)) islands--;
                }
                if (j > 0 && grid[i][j-1] == '1') {
                    if (uf.union(i*n+j, i*n+j-1)) islands--;
                }
            }
        }
    }
    return islands;
}

class SegmentTree {
    private int[] tree;
    private int n;

    public SegmentTree(int[] nums) {
        n = nums.length;
        tree = new int[4 * n];
        build(nums, 0, 0, n - 1);
    }

    private void build(int[] nums, int node, int start, int end) {
        if (start == end) {
            tree[node] = nums[start];
        } else {
            int mid = (start + end) / 2;
            build(nums, 2*node+1, start, mid);
            build(nums, 2*node+2, mid+1, end);
            tree[node] = tree[2*node+1] + tree[2*node+2];
        }
    }

    public void update(int idx, int val, int node, int start, int end) {
        if (start == end) {
            tree[node] = val;
        } else {
            int mid = (start + end) / 2;
            if (idx <= mid) update(idx, val, 2*node+1, start, mid);
            else update(idx, val, 2*node+2, mid+1, end);
            tree[node] = tree[2*node+1] + tree[2*node+2];
        }
    }

    public int query(int l, int r, int node, int start, int end) {
        if (r < start || end < l) return 0; // outside
        if (l <= start && end <= r) return tree[node]; // fully inside
        int mid = (start + end) / 2;
        return query(l, r, 2*node+1, start, mid)
             + query(l, r, 2*node+2, mid+1, end);
    }

    // Public wrappers
    public void update(int idx, int val) { update(idx, val, 0, 0, n-1); }
    public int query(int l, int r) { return query(l, r, 0, 0, n-1); }
}

// Simpler: iterative segment tree (1-indexed, size 2n)
class SegmentTreeIterative {
    private int[] tree;
    private int n;

    public SegmentTreeIterative(int[] nums) {
        n = nums.length;
        tree = new int[2 * n];
        // Load leaves
        for (int i = 0; i < n; i++) tree[i + n] = nums[i];
        // Build parents
        for (int i = n - 1; i >= 1; i--) tree[i] = tree[2*i] + tree[2*i+1];
    }

    public void update(int i, int val) {
        i += n;
        tree[i] = val;
        while (i > 1) { i /= 2; tree[i] = tree[2*i] + tree[2*i+1]; }
    }

    public int query(int l, int r) { // inclusive [l, r]
        int res = 0;
        for (l += n, r += n + 1; l < r; l /= 2, r /= 2) {
            if ((l & 1) == 1) res += tree[l++];
            if ((r & 1) == 1) res += tree[--r];
        }
        return res;
    }
}

class FenwickTree {
    private int[] bit;
    private int n;

    public FenwickTree(int n) {
        this.n = n;
        bit = new int[n + 1]; // 1-indexed
    }

    public FenwickTree(int[] nums) {
        this(nums.length);
        for (int i = 0; i < nums.length; i++) update(i + 1, nums[i]);
    }

    // Add delta to position i (1-indexed)
    public void update(int i, int delta) {
        for (; i <= n; i += (i & -i))
            bit[i] += delta;
    }

    // Prefix sum [1..i] (1-indexed)
    public int query(int i) {
        int sum = 0;
        for (; i > 0; i -= (i & -i))
            sum += bit[i];
        return sum;
    }

    // Range sum [l..r] (1-indexed, inclusive)
    public int rangeQuery(int l, int r) {
        return query(r) - query(l - 1);
    }
}

// Count inversions using BIT
public int countInversions(int[] nums) {
    // Coordinate compress to [1..n]
    int n = nums.length;
    int[] sorted = nums.clone();
    Arrays.sort(sorted);
    Map<Integer, Integer> rank = new HashMap<>();
    for (int i = 0; i < n; i++) rank.put(sorted[i], i + 1);

    FenwickTree bit = new FenwickTree(n);
    int inversions = 0;
    for (int i = n - 1; i >= 0; i--) {
        int r = rank.get(nums[i]);
        inversions += bit.query(r - 1); // count elements smaller than nums[i] seen so far
        bit.update(r, 1);
    }
    return inversions;
}
